import React, {useEffect, useState} from 'react';
import {View, Text, TextInput, TouchableOpacity, Alert, Platform, StyleSheet} from 'react-native';
import AsyncStorage from '@react-native-async-storage/async-storage';
import ReactNativeBiometrics from 'react-native-biometrics';

const AUTH_KEY = 'authenticated';
const USERNAME_KEY = 'saved_username';
const PASSWORD_KEY = 'saved_password';

const rnBiometrics = new ReactNativeBiometrics({
  allowDeviceCredentials: true,
});

const authenticateWithBiometrics = async () => {
  try {
    const {available, biometryType} = await rnBiometrics.isSensorAvailable();
    if (!available) return false;

    const result = await rnBiometrics.simplePrompt({
      promptMessage:
        biometryType === ReactNativeBiometrics.Biometrics.FaceID
          ? 'Authenticate with Face ID'
          : 'Authenticate with biometrics',
      cancelButtonText: 'Cancel',
    });

    return !!result?.success;
  } catch (e) {
    return false;
  }
};

const LoginScreen = ({onLoginSuccess}) => {
  const [username, setUsername] = useState('');
  const [password, setPassword] = useState('');
  const [loading, setLoading] = useState(false);

  const handleLogin = async () => {
    if (!username || !password) {
      Alert.alert('Error', 'Please enter username and password.');
      return;
    }

    setLoading(true);
    try {
      await AsyncStorage.setItem(USERNAME_KEY, username);
      await AsyncStorage.setItem(PASSWORD_KEY, password);
      await AsyncStorage.setItem(AUTH_KEY, 'true');
      onLoginSuccess();
    } catch (e) {
      Alert.alert('Error', 'Unable to save login state.');
    } finally {
      setLoading(false);
    }
  };

  const handleBiometricLogin = async () => {
    setLoading(true);
    try {
      const success = await authenticateWithBiometrics();
      if (success) {
        await AsyncStorage.setItem(AUTH_KEY, 'true');
        onLoginSuccess();
      } else {
        Alert.alert('Authentication failed', 'Use password to continue.');
      }
    } finally {
      setLoading(false);
    }
  };

  return (
    <View style={styles.container}>
      <Text style={styles.title}>Login</Text>

      <TextInput
        style={styles.input}
        placeholder="Username"
        autoCapitalize="none"
        value={username}
        onChangeText={setUsername}
      />

      <TextInput
        style={styles.input}
        placeholder="Password"
        secureTextEntry
        value={password}
        onChangeText={setPassword}
      />

      <TouchableOpacity
        style={[styles.button, loading && styles.buttonDisabled]}
        onPress={handleLogin}
        disabled={loading}>
        <Text style={styles.buttonText}>Login with Password</Text>
      </TouchableOpacity>

      <TouchableOpacity
        style={[styles.button, styles.bioButton, loading && styles.buttonDisabled]}
        onPress={handleBiometricLogin}
        disabled={loading}>
        <Text style={styles.buttonText}>Use Face ID / Fingerprint</Text>
      </TouchableOpacity>
    </View>
  );
};

const HomeScreen = ({onLogout}) => {
  const handleLogout = async () => {
    await AsyncStorage.removeItem(AUTH_KEY);
    onLogout();
  };

  return (
    <View style={styles.container}>
      <Text style={styles.title}>Home</Text>
      <Text>You are authenticated.</Text>
      <TouchableOpacity style={styles.button} onPress={handleLogout}>
        <Text style={styles.buttonText}>Logout</Text>
      </TouchableOpacity>
    </View>
  );
};

export default function App() {
  const [loading, setLoading] = useState(true);
  const [authenticated, setAuthenticated] = useState(false);

  useEffect(() => {
    const bootstrap = async () => {
      try {
        const flag = await AsyncStorage.getItem(AUTH_KEY);
        setAuthenticated(flag === 'true');
      } finally {
        setLoading(false);
      }
    };
    bootstrap();
  }, []);

  if (loading) {
    return (
      <View style={styles.container}>
        <Text>Loading...</Text>
      </View>
    );
  }

  if (authenticated) {
    return <HomeScreen onLogout={() => setAuthenticated(false)} />;
  }

  return <LoginScreen onLoginSuccess={() => setAuthenticated(true)} />;
}

